// Lightweight wrapper to allow dynamic import to succeed if the real library is not provided.
// Replace this file with the real qr-scanner library for production camera scanning.
export default class QrScanner {
  constructor(video, onDecode, options) {
    this.video = video;
    this.onDecode = onDecode;
    this.options = options;
  }
  start() { return Promise.reject(new Error('Camera scanning shim in use. Enter QR manually.')); }
  stop() {}
  destroy() {}
}

